export default SuperAdminDashboard;

import { supabase } from './supabaseClient';
import { Client, LogEntry, User, Agent } from '../types';

// Initial Seed for Milztech Admin
const SUPER_ADMIN_CREDENTIALS = {
  username: 'milztech',
  password: 'admin' 
};

// --- Authentication ---

export const authenticateUser = async (username: string, password: string): Promise<User | null> => {
  // 1. Check Super Admin (Hardcoded for Developer Access)
  if (username === SUPER_ADMIN_CREDENTIALS.username && password === SUPER_ADMIN_CREDENTIALS.password) {
    return {
      id: 'super-admin',
      username: 'milztech',
      name: 'Milztech Admin',
      role: 'SUPER_ADMIN'
    };
  }

  try {
    // 2. Check Client Admins
    const { data: clientData, error: clientError } = await supabase
      .from('clients')
      .select('*')
      .eq('username', username)
      .eq('password', password)
      .single();

    if (clientData && !clientError) {
      return {
        id: clientData.id,
        username: clientData.username,
        name: clientData.name,
        role: 'CLIENT_ADMIN',
        clientId: clientData.id
      };
    }

    // 3. Check Agents
    const { data: agentData, error: agentError } = await supabase
      .from('agents')
      .select('*, clients(id, name)')
      .eq('username', username)
      .eq('password', password)
      .single();

    if (agentData && !agentError) {
      return {
        id: agentData.id,
        username: agentData.username,
        name: agentData.name,
        role: 'AGENT',
        clientId: agentData.client_id
      };
    }
  } catch (err) {
    console.error("Auth DB Error:", err);
  }

  return null;
};

// --- Client Management (Super Admin) ---

export const getAllClients = async (): Promise<Client[]> => {
  const { data, error } = await supabase
    .from('clients')
    .select('*, agents(*)');

  if (error) {
    console.error("Error fetching clients:", error);
    return [];
  }
  return data || [];
};

export const addClient = async (name: string, username: string, password: string): Promise<void> => {
  const { data: existing } = await supabase.from('clients').select('id').eq('username', username).single();
  if (existing) throw new Error('このユーザーIDは既に使用されています');

  const { error } = await supabase
    .from('clients')
    .insert([{ name, username, password }]);

  if (error) throw error;
};

export const deleteClient = async (clientId: string): Promise<void> => {
  const { error } = await supabase
    .from('clients')
    .delete()
    .eq('id', clientId);

  if (error) throw error;
};

// --- Agent Management (Client Admin) ---

export const getClientAgents = async (clientId: string): Promise<Agent[]> => {
  const { data, error } = await supabase
    .from('agents')
    .select('*')
    .eq('client_id', clientId);

  if (error) {
    console.error("Error fetching agents:", error);
    return [];
  }
  return data || [];
};

export const addAgent = async (clientId: string, name: string, username: string, password: string): Promise<void> => {
  const { error } = await supabase
    .from('agents')
    .insert([{ client_id: clientId, name, username, password }]);

  if (error) {
    if (error.code === '23505') throw new Error('このユーザーIDは既に使用されています');
    throw error;
  }
};

export const deleteAgent = async (agentId: string): Promise<void> => {
  const { error } = await supabase
    .from('agents')
    .delete()
    .eq('id', agentId);

  if (error) throw error;
};

// --- Logs ---

export const addLog = async (entry: Partial<LogEntry>): Promise<void> => {
  const { id, timestamp, ...payload } = entry as any;

  const { error } = await supabase
    .from('logs')
    .insert([{
      ...payload,
      timestamp: new Date().toISOString()
    }]);

  if (error) console.error("Error adding log:", error);
};

export const getLogsByClient = async (clientId: string): Promise<LogEntry[]> => {
  const { data, error } = await supabase
    .from('logs')
    .select('*')
    .eq('client_id', clientId)
    .order('timestamp', { ascending: false });

  if (error) return [];
  return data || [];
};

export const getAllLogs = async (): Promise<LogEntry[]> => {
  const { data, error } = await supabase
    .from('logs')
    .select('*')
    .order('timestamp', { ascending: false });

  if (error) return [];
  return data || [];
};

export const generateUniqueId = (): string => {
  return crypto.randomUUID();
};

import React, { useState, useEffect } from 'react';
import { LogEntry, Agent, User } from '../types';
import { getLogsByClient, getClientAgents, addAgent, deleteAgent } from '../services/storageService';

interface DashboardProps {
  currentUser: User;
}

const Dashboard: React.FC<DashboardProps> = ({ currentUser }) => {
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [agents, setAgents] = useState<Agent[]>([]);
  const [selectedLog, setSelectedLog] = useState<LogEntry | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Agent Form
  const [newAgentName, setNewAgentName] = useState('');
  const [newAgentUser, setNewAgentUser] = useState('');
  const [newAgentPass, setNewAgentPass] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    if (currentUser.clientId) {
      refreshData();
    }
  }, [currentUser]);

  const refreshData = async () => {
    if (!currentUser.clientId) return;
    setIsLoading(true);
    try {
      const [fetchedLogs, fetchedAgents] = await Promise.all([
        getLogsByClient(currentUser.clientId),
        getClientAgents(currentUser.clientId)
      ]);
      setLogs(fetchedLogs);
      setAgents(fetchedAgents);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAddAgent = async () => {
    if (!currentUser.clientId) return;
    if (!newAgentName || !newAgentUser || !newAgentPass) {
      setError('全ての項目を入力してください');
      return;
    }

    try {
      await addAgent(currentUser.clientId, newAgentName, newAgentUser, newAgentPass);
      setNewAgentName('');
      setNewAgentUser('');
      setNewAgentPass('');
      setError('');
      refreshData();
    } catch (e: any) {
      setError(e.message);
    }
  };

  const handleDeleteAgent = async (agentId: string) => {
    if (!currentUser.clientId) return;
    if (window.confirm('このエージェントを削除しますか？')) {
      await deleteAgent(agentId);
      refreshData();
    }
  };

  const totalGenerations = logs.length;
  // Stats for Search Usage
  const searchOnCount = logs.filter(l => l.search_used).length;
  const searchOffCount = logs.filter(l => !l.search_used).length;

  const today = new Date().toISOString().slice(0, 10);
  const todaysCount = logs.filter(log => log.timestamp.slice(0, 10) === today).length;

  return (
    <div className="space-y-8">
      {isLoading && (
        <div className="fixed inset-0 bg-white bg-opacity-70 z-40 flex items-center justify-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-orange-500"></div>
        </div>
      )}

      {/* Client Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
          <h3 className="text-sm font-medium text-gray-500">本日の作成数</h3>
          <p className="text-3xl font-bold text-gray-900 mt-2">{todaysCount} <span className="text-sm font-normal text-gray-400">件</span></p>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
          <h3 className="text-sm font-medium text-gray-500">検索機能 利用回数</h3>
          <div className="flex items-end mt-2">
            <p className="text-3xl font-bold text-orange-600">{searchOnCount}</p>
            <p className="text-gray-400 text-sm ml-2 mb-1">/ OFF: {searchOffCount}</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
          <h3 className="text-sm font-medium text-gray-500">累計作成数</h3>
          <p className="text-3xl font-bold text-gray-900 mt-2">{totalGenerations} <span className="text-sm font-normal text-gray-400">件</span></p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Agent Management */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 lg:col-span-1 h-fit">
          <h2 className="text-lg font-bold text-gray-900 mb-4 flex items-center">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 mr-2 text-orange-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0z" />
            </svg>
