`;

  if (referenceUrl) {
    userPrompt += `参考Webサイト: ${referenceUrl}\n`;
  }

  if (pdfFile) {
    userPrompt += `\n※添付のPDFファイルの詳細スペックを反映してください。\n`;
  }

  if (useSearch) {
    userPrompt += `\n指示: Google検索を使用して、この住所周辺の最新の生活利便施設、交通事情、治安などをリサーチし、購入検討者に有益な具体的情報（施設名や距離など）を盛り込んでください。\n`;
  } else {
    userPrompt += `\n指示: Google検索は使用しないでください。入力された情報のみで構成してください。\n`;
  }

  try {
    const parts: Part[] = [{ text: userPrompt }];

    if (base64Pdf) {
      parts.push({
        inlineData: {
          mimeType: 'application/pdf',
          data: base64Pdf
        }
      });
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ role: 'user', parts: parts }],
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.3, 
        tools: useSearch ? [{ googleSearch: {} }] : []
      }
    });

    const text = response.text || "生成に失敗しました。";

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const urls: string[] = [];
    groundingChunks.forEach(chunk => {
      if (chunk.web?.uri) {
        urls.push(chunk.web.uri);
      }
    });

    return { text, groundingUrls: [...new Set(urls)] };

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

