import { GoogleGenAI, Part, GenerateContentResponse } from "@google/genai";
import { FLATTENED_FORBIDDEN_WORDS } from "../constants";

const convertFileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = error => reject(error);
  });
};

export const generatePropertyDescriptionStream = async (
  propertyName: string,
  address: string,
  pdfFile: File | null,
  referenceUrl: string,
  useSearch: boolean,
  onChunk: (text: string) => void
): Promise<{ fullText: string; groundingUrls: string[] }> => {

  const apiKey = process.env.API_KEY || process.env.VITE_GEMINI_API_KEY;

  if (!apiKey) {
    throw new Error("APIキーが設定されていません。環境変数（API_KEY）を確認してください。");
  }

  const ai = new GoogleGenAI({ apiKey: apiKey });

  let base64Pdf: string | null = null;
  if (pdfFile) {
    base64Pdf = await convertFileToBase64(pdfFile);
  }

  const forbiddenListString = FLATTENED_FORBIDDEN_WORDS.join(', ');

  const systemInstruction = `
あなたは不動産公正取引協議会の規約を厳格に遵守する、エリート不動産コピーライターです。
${useSearch ? 'Google検索を使用して、周辺施設（スーパー、病院、公園等）の具体的な名称と物件からの距離を正確に調査してください。' : '提供された情報のみを使用してください。'}

【絶対遵守：禁止用語】
以下の単語は使用禁止です：${forbiddenListString}
「最高」「格安」「日本一」「心理的瑕疵」「告知事項」等は一切含めないでください。

【作成ルール】
1. 文字数: 450〜550文字程度。
2. 物件名「${propertyName}」を必ず含める。
3. 建物スペック、交通アクセス、周辺環境を具体的に記述。
4. 誇大広告にならないよう、客観的事実に基づいた魅力付けを行う。

出力は、紹介文のテキストのみとしてください。
`;

  let userPrompt = `物件名: ${propertyName}\n住所: ${address}\n`;
  if (referenceUrl) userPrompt += `参考URL: ${referenceUrl}\n`;
  if (pdfFile) userPrompt += `※添付PDFのスペックを反映してください。\n`;

  try {
    const parts: Part[] = [{ text: userPrompt }];
    if (base64Pdf) {
      parts.push({
        inlineData: {
          mimeType: 'application/pdf',
          data: base64Pdf
        }
      });
    }

    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: [{ role: 'user', parts: parts }],
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.3, 
        tools: useSearch ? [{ googleSearch: {} }] : []
      }
    });

    let fullText = "";
    let groundingUrls: string[] = [];

    for await (const chunk of responseStream) {
      const textChunk = chunk.text;
      if (textChunk) {
        fullText += textChunk;
        onChunk(fullText);
      }

      // Extract grounding metadata if available in any chunk
      const chunks = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (chunks) {
        chunks.forEach(c => {
          if (c.web?.uri) groundingUrls.push(c.web.uri);
        });
      }
    }

    return { 
      fullText, 
      groundingUrls: [...new Set(groundingUrls)] 
    };

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    if (error.message?.includes("candidate was blocked")) {
      throw new Error("不適切な表現が含まれる可能性があるため、AIが生成を中断しました。物件情報を見直してください。");
    }
    throw new Error("生成に失敗しました。ネットワーク状況を確認し、再度お試しください。");
  }
};

import React, { useState, useEffect } from 'react';
import { FormData, GenerationResult, ViewState, User, Agent } from './types';
import { generatePropertyDescriptionStream } from './services/geminiService';
import { authenticateUser, addLog, getClientAgents } from './services/storageService';
import InputForm from './components/InputForm';
import ResultDisplay from './components/ResultDisplay';
import LoginScreen from './components/LoginScreen';
import Dashboard from './components/Dashboard';
import SuperAdminDashboard from './components/SuperAdminDashboard';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    try {
      const saved = localStorage.getItem('estate_app_user_session');
      return saved ? JSON.parse(saved) : null;
    } catch (e) {
      return null;
    }
  });

  const [loginError, setLoginError] = useState<string | null>(null);
  const [isAuthLoading, setIsAuthLoading] = useState(false);
  const [view, setView] = useState<ViewState>('login');

  const [formData, setFormData] = useState<FormData>({
    propertyName: '',
    address: '',
    pdfFile: null,
    referenceUrl: '',
    selectedAgentId: '' 
  });

  const [useSearch, setUseSearch] = useState(() => {
    const saved = localStorage.getItem('estate_app_use_search');
    return saved !== null ? JSON.parse(saved) : true;
  });

  const [result, setResult] = useState<GenerationResult | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [loadingStep, setLoadingStep] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [availableAgents, setAvailableAgents] = useState<Agent[]>([]);

  useEffect(() => {
    localStorage.setItem('estate_app_use_search', JSON.stringify(useSearch));
  }, [useSearch]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('estate_app_user_session', JSON.stringify(currentUser));
      if (currentUser.clientId) {
        getClientAgents(currentUser.clientId).then(agents => setAvailableAgents(agents));
      }

      if (view === 'login') {
        if (currentUser.role === 'SUPER_ADMIN') setView('super_dashboard');
        else if (currentUser.role === 'CLIENT_ADMIN') setView('client_dashboard');
        else setView('generator');
      }
    } else {
      localStorage.removeItem('estate_app_user_session');
      setView('login');
    }
  }, [currentUser]);

  const handleLogin = async (u: string, p: string) => {
    setLoginError(null);
    setIsAuthLoading(true);
    try {
      const user = await authenticateUser(u, p);
      if (user) setCurrentUser(user);
      else setLoginError('IDまたはパスワードが正しくありません');
    } catch (e) {
      setLoginError('ログイン中にエラーが発生しました');
    } finally {
      setIsAuthLoading(false);
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setResult(null);
    setFormData({ propertyName: '', address: '', pdfFile: null, referenceUrl: '', selectedAgentId: '' });
  };

  const handleSubmit = async () => {
    if (!formData.propertyName || !formData.address || !formData.selectedAgentId || !currentUser) return;

    setIsLoading(true);
    setError(null);
    setResult({ text: '生成を開始しています...', characterCount: 0, groundingUrls: [] });
    setLoadingStep('リサーチを開始しています...');

    try {
      if (useSearch) {
        setTimeout(() => setLoadingStep('周辺情報をGoogle検索で調査中...'), 3000);
        setTimeout(() => setLoadingStep('最新の施設情報を取得中...'), 8000);
      } else {
        setTimeout(() => setLoadingStep('提供資料を解析中...'), 2000);
      }
      setTimeout(() => setLoadingStep('紹介文を構成中...'), 15000);

      const response = await generatePropertyDescriptionStream(
        formData.propertyName,
        formData.address,
        formData.pdfFile,
        formData.referenceUrl,
        useSearch,
        (currentText) => {
          setLoadingStep('文章を書き出し中...');
          setResult({
            text: currentText,
            characterCount: currentText.replace(/\s/g, '').length,
            groundingUrls: []
          });
        }
      );

      const finalCount = response.fullText.replace(/\s/g, '').length;
      const finalResult = {
        text: response.fullText,
        characterCount: finalCount,
        groundingUrls: response.groundingUrls
      };

      setResult(finalResult);
      setLoadingStep('');

      if (currentUser.clientId) {
        const agentName = availableAgents.find(a => a.id === formData.selectedAgentId)?.name || 'Unknown';
        await addLog({
          client_id: currentUser.clientId,
          agent_id: formData.selectedAgentId,
          agent_name: agentName,
          property_name: formData.propertyName,
          address: formData.address,
          result_text: response.fullText,
          grounding_urls: response.groundingUrls,
          search_used: useSearch
        });
      }

    } catch (err: any) {
      setError(err.message || "生成中にエラーが発生しました。");
      setResult(null);
    } finally {
      setIsLoading(false);
      setLoadingStep('');
    }
  };

  if (!currentUser) {
    return <LoginScreen onLogin={handleLogin} loginError={loginError} isLoading={isAuthLoading} />;
  }

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 font-sans pb-12">
      <header className="bg-black text-white shadow-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-8">
            <div className="flex items-center space-x-3 cursor-pointer" onClick={() => {
              if (currentUser.role === 'SUPER_ADMIN') setView('super_dashboard');
              else if (currentUser.role === 'CLIENT_ADMIN') setView('client_dashboard');
              else setView('generator');
            }}>
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-orange-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
              </svg>
              <div>
                <h1 className="text-xl font-bold tracking-wide">EstateCopy AI</h1>
                <span className="text-[10px] text-gray-400 block -mt-1 uppercase tracking-widest">{currentUser.role.replace('_', ' ')}</span>
              </div>
            </div>

            <nav className="hidden md:flex space-x-1">
              {currentUser.role !== 'AGENT' && (
                <button 
                  onClick={() => setView(currentUser.role === 'SUPER_ADMIN' ? 'super_dashboard' : 'client_dashboard')}
                  className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${view.includes('dashboard') ? 'bg-zinc-800 text-white' : 'text-gray-400 hover:text-white'}`}
                >
                  ダッシュボード
                </button>
              )}
              <button 
                onClick={() => setView('generator')}
                className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${view === 'generator' ? 'bg-orange-600 text-white' : 'text-gray-400 hover:text-white'}`}
              >
                新規作成
              </button>
            </nav>
          </div>

          <div className="flex items-center space-x-4">
             <div className="hidden sm:flex flex-col items-end mr-2">
                <span className="text-xs font-bold text-gray-200">{currentUser.name}</span>
                <span className="text-[10px] text-gray-500">{currentUser.username}</span>
             </div>
             <button onClick={handleLogout} className="text-gray-400 hover:text-white p-2">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
                </svg>
             </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {view === 'super_dashboard' && <SuperAdminDashboard />}
        {view === 'client_dashboard' && <Dashboard currentUser={currentUser} />}
        {view === 'generator' && (
          <>
            {error && (
              <div className="mb-6 bg-red-50 border-l-4 border-red-500 text-red-700 px-4 py-3 rounded shadow-sm flex items-center">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 mr-3" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
                </svg>
                <span className="font-medium">{error}</span>
              </div>
            )}

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">
              <InputForm 
                formData={formData} 
                setFormData={setFormData} 
                onSubmit={handleSubmit} 
                isLoading={isLoading} 
                agents={availableAgents}
                currentUser={currentUser}
                useSearch={useSearch}
                setUseSearch={setUseSearch}
              />
              <div className="relative">
                {isLoading && loadingStep && (
                  <div className="absolute -top-12 left-0 right-0 text-center">
                    <div className="inline-flex items-center px-4 py-2 bg-orange-100 text-orange-700 text-sm font-bold rounded-full shadow-sm animate-pulse border border-orange-200">
                      <svg className="animate-spin h-4 w-4 mr-2 text-orange-600" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                      {loadingStep}
                    </div>
                  </div>
                )}
                <ResultDisplay 
                  result={result} 
                  onRetry={handleSubmit} 
                  isLoading={isLoading} 
                />
              </div>
            </div>
          </>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
import { GenerationResult } from '../types';
import { FLATTENED_FORBIDDEN_WORDS, REPLACEMENT_SUGGESTIONS } from '../constants';

interface ResultDisplayProps {
  result: GenerationResult | null;
  onRetry: () => void;
  isLoading: boolean;
}

const ResultDisplay: React.FC<ResultDisplayProps> = ({ result, onRetry, isLoading }) => {
  if (!result) {
    return (
      <div className="bg-gray-100 rounded-xl border-2 border-dashed border-gray-200 p-12 h-[600px] flex flex-col items-center justify-center text-gray-400">
        <div className="bg-white p-4 rounded-full shadow-inner mb-4">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 20H5a2 2 0 01-2-2V6a2 2 0 012-2h10a2 2 0 012 2v1m2 13a2 2 0 01-2-2V7m2 13a2 2 0 002-2V9a2 2 0 00-2-2h-2m-4-3H9M7 16h6M7 8h6v4H7V8z" />
          </svg>
        </div>
        <p className="font-medium">物件情報を入力して生成を開始してください</p>
        <p className="text-xs mt-1">AIが自動的に規約チェックと周辺調査を行います</p>
      </div>
    );
  }

  // Safety check: Scan the result text for any forbidden words
  const detectedForbiddenWords = useMemo(() => {
    // Only check if it looks like a final or substantial result (not just the start message)
    if (result.text === '生成を開始しています...') return [];
    return FLATTENED_FORBIDDEN_WORDS.filter(word => result.text.includes(word));
  }, [result.text]);

  const hasViolation = detectedForbiddenWords.length > 0;

  const getHighlightedText = () => {
    if (result.text === '生成を開始しています...') {
      return <p className="text-gray-400 italic">AIが思考を整理しています...</p>;
    }

    if (!hasViolation) {
      return <p className="whitespace-pre-wrap leading-relaxed text-gray-800">{result.text}</p>;
    }

    let highlightedContent = result.text;
    detectedForbiddenWords.forEach(word => {
      const regex = new RegExp(word, 'g');
      highlightedContent = highlightedContent.replace(regex, `<span class="bg-red-100 text-red-700 font-bold px-1 rounded border border-red-200 underline decoration-red-300 decoration-2">${word}</span>`);
    });

    return (
      <div 
        className="whitespace-pre-wrap leading-relaxed text-gray-800"
        dangerouslySetInnerHTML={{ __html: highlightedContent }}
      />
    );
  };

  const isLengthValid = result.characterCount >= 450 && result.characterCount <= 550;
  const isGenerating = isLoading || result.text === '生成を開始しています...';

  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 h-full min-h-[600px] flex flex-col">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-xl font-bold text-gray-900 flex items-center">
          <span className={`w-2 h-6 bg-orange-500 rounded-full mr-3 ${isGenerating ? 'animate-pulse' : ''}`}></span>
          生成結果
        </h2>
        <div className={`px-4 py-1.5 rounded-full text-sm font-bold border transition-colors ${
          isGenerating ? 'bg-gray-50 text-gray-400 border-gray-200' :
          isLengthValid ? 'bg-green-50 text-green-700 border-green-200' : 
          'bg-red-50 text-red-700 border-red-200'
        }`}>
          {result.characterCount} 文字
        </div>
      </div>

      {hasViolation && !isGenerating && (
        <div className="mb-6 bg-red-50 border border-red-200 p-4 rounded-lg shadow-sm">
          <div className="flex items-center mb-3">
            <svg className="h-5 w-5 text-red-500 mr-2" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
            </svg>
            <p className="text-sm text-red-700 font-bold">
              規約違反の単語が検出されました
            </p>
          </div>
          <div className="space-y-2">
            {detectedForbiddenWords.map(word => (
              <div key={word} className="text-xs bg-white p-2 rounded border border-red-100 shadow-sm flex flex-col sm:flex-row sm:items-center">
                <span className="font-bold text-red-600">× {word}</span>
                <span className="hidden sm:inline mx-2 text-gray-300">→</span>
                <span className="text-gray-600 italic">
                  修正案: {REPLACEMENT_SUGGESTIONS[word] || '具体的・客観的な事実に書き換えてください'}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}

      <div className={`flex-grow p-6 rounded-xl border transition-all duration-500 overflow-y-auto max-h-[600px] ${
        isGenerating ? 'bg-gray-50 border-gray-100' : 'bg-orange-50 bg-opacity-30 border-orange-100'
      }`}>
        {getHighlightedText()}
      </div>

      <div className="mt-6 flex flex-col sm:flex-row justify-between items-center gap-4">
        <div className="text-xs font-medium">
          {!isGenerating && !isLengthValid && (
            <span className="text-red-500 flex items-center">
              <svg className="w-4 h-4 mr-1" fill="currentColor" viewBox="0 0 20 20">
                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
              </svg>
              推奨範囲(450〜550文字)から外れています
            </span>
          )}
        </div>
        <div className="flex items-center space-x-3 w-full sm:w-auto">
          <button
            onClick={onRetry}
            disabled={isLoading}
            className={`flex-1 sm:flex-none flex justify-center items-center font-bold px-6 py-2.5 rounded-lg border transition-all ${
              isLoading 
                ? 'bg-gray-100 text-gray-400 border-gray-200 cursor-not-allowed' 
                : 'bg-white text-gray-700 border-gray-300 hover:border-orange-500 hover:text-orange-600 hover:shadow-sm'
            }`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className={`h-5 w-5 mr-2 ${isLoading ? 'animate-spin' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
            再生成
          </button>

          <button
            onClick={() => {
              navigator.clipboard.writeText(result.text);
              alert('コピーしました');
            }}
            disabled={isGenerating}
            className={`flex-1 sm:flex-none flex justify-center items-center font-bold px-6 py-2.5 rounded-lg transition-all shadow-sm ${
              isGenerating ? 'bg-gray-400 cursor-not-allowed' : 'bg-black text-white hover:bg-gray-800'
            }`}
          >
            コピー
          </button>
        </div>
      </div>

      {result.groundingUrls.length > 0 && !isLoading && (
        <div className="mt-6 pt-6 border-t border-gray-100">
          <div className="flex items-center text-xs font-bold text-gray-500 mb-3">
            <svg className="w-3 h-3 mr-1 text-orange-500" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M12.586 4.586a2 2 0 112.828 2.828l-3 3a2 2 0 01-2.828 0 1 1 0 00-1.414 1.414 4 4 0 005.656 0l3-3a4 4 0 00-5.656-5.656l-1.5 1.5a1 1 0 101.414 1.414l1.5-1.5zm-5 5a2 2 0 012.828 0 1 1 0 101.414-1.414 4 4 0 00-5.656 0l-3 3a4 4 0 105.656 5.656l1.5-1.5a1 1 0 10-1.414-1.414l-1.5 1.5a2 2 0 11-2.828-2.828l3-3z" clipRule="evenodd" />
            </svg>
            参照したWebソース
          </div>
          <div className="flex flex-wrap gap-2">
            {result.groundingUrls.map((url, idx) => (
              <a 
                key={idx} 
                href={url} 
                target="_blank" 
                rel="noopener noreferrer" 
                className="text-[10px] bg-gray-50 text-orange-600 px-2 py-1 rounded border border-gray-100 hover:bg-orange-50 transition-colors truncate max-w-[200px]"
              >
                {url}
              </a>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

