          </label>
          <div className="relative border-2 border-dashed border-gray-300 rounded-lg p-6 hover:bg-gray-50 hover:border-orange-300 transition-colors group bg-white">
            <input
              type="file"
              accept=".pdf"
              className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
              onChange={handleFileChange}
              disabled={isLoading}
            />
            <div className="text-center pointer-events-none">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 mx-auto text-gray-400 group-hover:text-orange-500 transition-colors mb-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
              </svg>
              {formData.pdfFile ? (
                <p className="text-orange-600 font-medium break-all">{formData.pdfFile.name}</p>
              ) : (
                <div className="text-gray-500">
                  <p>クリックまたはドラッグ＆ドロップで</p>
                  <p>PDFからスペックを抽出</p>
                </div>
              )}
            </div>
          </div>
        </div>

        <button
          onClick={onSubmit}
          disabled={!isFormValid || isLoading}
          className={`w-full py-4 px-6 rounded-lg font-bold text-white shadow-sm transition-all duration-200 mt-4
            ${!isFormValid || isLoading 
              ? 'bg-gray-300 cursor-not-allowed text-gray-500' 
              : 'bg-orange-600 hover:bg-orange-700 hover:shadow-md transform hover:-translate-y-0.5'
            }`}
        >
          {isLoading ? (
            <span className="flex items-center justify-center">
              <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              規約に基づき生成中...
            </span>
          ) : (
            '説明文を作成する'
          )}
        </button>
      </div>
    </div>
  );
};

