export const generatePropertyDescriptionStream = async (
  propertyName: string,
  address: string,
  pdfFile: File | null,
  referenceUrl: string,
  useSearch: boolean,
  onChunk: (text: string) => void,
  buildingAge?: string,
  totalUnits?: string
): Promise<{ fullText: string; groundingUrls: string[] }> => {

  const apiKey = process.env.API_KEY || process.env.VITE_GEMINI_API_KEY;

  if (!apiKey) {
    throw new Error("APIキーが設定されていません。");
  }

  const ai = new GoogleGenAI({ apiKey: apiKey });

  let base64Pdf: string | null = null;
  if (pdfFile) {
    base64Pdf = await convertFileToBase64(pdfFile);
  }

  const forbiddenListString = FLATTENED_FORBIDDEN_WORDS.join(', ');

  const systemInstruction = `
あなたは不動産広告の正確性とコンプライアンスを司る、厳格なデータ検証員兼ライターです。
「正確性」が最も重要です。以下のルールを**例外なく**適用してください。

【情報源の絶対優先順位】
1. ユーザー入力値（築年数: ${buildingAge || '未指定'}、総戸数: ${totalUnits || '未指定'}）
   → これらが指定されている場合、検索結果やPDFに何と書いてあっても、この値を「絶対的な真実」として使用してください。
2. 添付されたPDFファイルの内容
3. Google検索による公式・ポータルサイトの情報

【事実確認（ファクトチェック）プロトコル】
・推測を厳禁します：情報が見つからないスペック（構造、所在階など）について、周辺の似た物件から類推して書くことは絶対にやめてください。
・周辺施設の正確性：Google検索で「${address}」周辺の施設を探す際、必ず実在する名称と正確な距離（または徒歩分数）を確認してください。確証がない施設は記載しないでください。
・物件の取り違え防止：物件名「${propertyName}」が検索結果に含まれていても、住所「${address}」と一致しない場合は、その情報を無視してください。

【文章構成ルール】
1. 文字数: 450〜550文字程度。
2. 物件名「${propertyName}」を必ず含める。
3. 築年数と総戸数を、文中の事実として明確に記載する。
4. 交通アクセスと周辺環境は、具体的かつ客観的に描写する。

【絶対遵守：禁止用語】
以下の単語は使用禁止です（不動産公正取引規約違反）：${forbiddenListString}
「最高」「格安」「資産価値」「日本一」などは一切含めないでください。

出力は、紹介文のテキストのみとしてください。
`;

  let userPrompt = `
【入力データ】
物件名: ${propertyName}
住所: ${address}
指定された築年数: ${buildingAge || '未入力（PDF/Webから取得してください）'}
指定された総戸数: ${totalUnits || '未入力（PDF/Webから取得してください）'}
参考URL: ${referenceUrl || 'なし'}

【作成指示】
1. 上記の指定データを最優先してください。
2. ${useSearch ? 'Google検索を使用して、周辺の公共施設、スーパー、教育機関、公園の実名と距離を調査してください。' : '検索は行わず、手元の情報のみで構成してください。'}
3. PDFが添付されている場合は、そこから建物構造や設備などの詳細スペックを抽出してください。
`;

  try {
    const parts: Part[] = [{ text: userPrompt }];
    if (base64Pdf) {
      parts.push({
        inlineData: {
          mimeType: 'application/pdf',
          data: base64Pdf
        }
      });
    }

    // 複雑な事実確認が必要なため、Proモデルを使用
    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-pro-preview',
      contents: [{ role: 'user', parts: parts }],
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.1, // 正確性を高めるため、ランダム性を最小限に
        tools: useSearch ? [{ googleSearch: {} }] : []
      }
    });

    let fullText = "";
    let groundingUrls: string[] = [];

    for await (const chunk of responseStream) {
      const textChunk = chunk.text;
      if (textChunk) {
        fullText += textChunk;
        onChunk(fullText);
      }

      const chunks = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (chunks) {
        chunks.forEach(c => {
          if (c.web?.uri) groundingUrls.push(c.web.uri);
        });
      }
    }

    return { 
      fullText, 
      groundingUrls: [...new Set(groundingUrls)] 
    };

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    if (error.message?.includes("candidate was blocked")) {
      throw new Error("コンプライアンス上の理由で生成が中断されました。");
    }
    throw new Error("生成中にエラーが発生しました。");
  }
};

