import { GoogleGenAI, Part, GenerateContentResponse } from "@google/genai";
import { FLATTENED_FORBIDDEN_WORDS } from "../constants";

const convertFileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = error => reject(error);
  });
};

export const generatePropertyDescriptionStream = async (
  propertyName: string,
  address: string,
  pdfFile: File | null,
  referenceUrl: string,
  useSearch: boolean,
  onChunk: (text: string) => void,
  buildingAge?: string,
  totalUnits?: string
): Promise<{ fullText: string; groundingUrls: string[] }> => {

  const apiKey = process.env.API_KEY || process.env.VITE_GEMINI_API_KEY;

  if (!apiKey) {
    throw new Error("APIキーが設定されていません。");
  }

  const ai = new GoogleGenAI({ apiKey: apiKey });

  let base64Pdf: string | null = null;
  if (pdfFile) {
    base64Pdf = await convertFileToBase64(pdfFile);
  }

  const forbiddenListString = FLATTENED_FORBIDDEN_WORDS.join(', ');

  const systemInstruction = `
あなたは不動産広告の「正確性」と「規約遵守」を極めた、専門のデータ検証コピーライターです。
信頼できない情報は一切排除し、事実に基づいた文章のみを作成してください。

【情報ソースの厳格な扱い】
1. ユーザー指定値（最優先）:
   ・築年数: ${buildingAge || '未指定'}
   ・総戸数: ${totalUnits || '未指定'}
   ※上記が入力されている場合、Web検索の結果と異なっても、必ずこの値を「正解」として使用してください。AIによる書き換えは厳禁です。

2. Google検索のフィルタリング（最重要）:
   ・不動産ポータルサイト（SUUMO, LIFULL HOME'S, athome 等）またはデベロッパーの公式サイトの情報のみを信頼してください。
   ・個人のブログ、無関係な掲示板、古いニュースサイトの情報は、たとえ物件名が一致していても採用しないでください。
   ・周辺施設（スーパー、病院等）の情報も、現在のGoogleマップや公式サイトで確認できる実在するもののみを記載してください。

3. 推論・推測の禁止:
   ・情報源に「竣工年」や「総戸数」の確実な記載がない場合、勝手に数字を捏造しないでください。
   ・不明なスペックは無理に書かず、周辺環境や物件の一般的な魅力（交通の便など）に重点を置いて構成してください。

【文章構成ルール】
1. 文字数: 450〜550文字程度。
2. 物件名「${propertyName}」を必ず含める。
3. 指定されたスペック（築年、戸数）を客観的な事実として明記する。

【絶対遵守：禁止用語】
以下の単語は使用禁止です：${forbiddenListString}
「最高」「格安」「資産価値」「日本一」などは一切含めないでください。

出力は、紹介文のテキストのみとしてください。
`;

  // 検索クエリをより具体的に絞り込むためのヒントをAIに与える
  let userPrompt = `
【最優先データ】
物件名: ${propertyName}
住所: ${address}
築年数: ${buildingAge || 'PDF/Webから正確に特定してください'}
総戸数: ${totalUnits || 'PDF/Webから正確に特定してください'}

【検索・作成指示】
1. Google検索を使用する場合、以下のキーワードを組み合わせて検索し、信頼性の高いポータルサイト（SUUMO, HOMES等）から正確なスペック（竣工年月・構造・戸数・施工・分譲）を特定してください：
   「${propertyName} ${address} 概要 竣工 総戸数 公式」
2. 周辺環境についても、上記住所から徒歩10分圏内（約800m）にある具体的なスーパー、教育機関、公園の実名とその距離（分表示）を確認して記載してください。
3. 参照URL（${referenceUrl || 'なし'}）がある場合は、その内容を優先してください。
4. PDFが添付されている場合は、スペック情報の最終確認として使用してください。
`;

  try {
    const parts: Part[] = [{ text: userPrompt }];
    if (base64Pdf) {
      parts.push({
        inlineData: {
          mimeType: 'application/pdf',
          data: base64Pdf
        }
      });
    }

    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-pro-preview',
      contents: [{ role: 'user', parts: parts }],
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.1, 
        tools: useSearch ? [{ googleSearch: {} }] : []
      }
    });

    let fullText = "";
    let groundingUrls: string[] = [];

    for await (const chunk of responseStream) {
      const textChunk = chunk.text;
      if (textChunk) {
        fullText += textChunk;
        onChunk(fullText);
      }

      const chunks = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (chunks) {
        chunks.forEach(c => {
          if (c.web?.uri) groundingUrls.push(c.web.uri);
        });
      }
    }

    // フィルタリング: 不動産関連でない、または怪しいドメインを特定し、
    // （ここではAIに任せるのが主ですが、表示されるURLリストも一意にします）
    return { 
      fullText, 
      groundingUrls: [...new Set(groundingUrls)] 
    };

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    if (error.message?.includes("candidate was blocked")) {
      throw new Error("コンプライアンス上の理由でAIが回答を制限しました。");
    }
    throw new Error("生成中にエラーが発生しました。");
  }
};

